SELECT ma.id, ma.patient_id, p.patient_name, p.mobile AS patient_mobile, ma.member_no, ma.level_id, ml.level_name, ma.balance_amount, ma.points_balance, ma.total_recharge_amount, ma.total_consume_amount, ma.member_status, ma.activated_at, ma.expired_at FROM member_account ma LEFT JOIN patient p ON p.id = ma.patient_id LEFT JOIN member_level ml ON ml.id = ma.level_id WHERE ma.org_id = #{orgId}
AND ( p.first_clinic_id IN
#{clinicId}
OR ma.patient_id IN ( SELECT patient_id FROM appointment WHERE clinic_id IN
#{clinicId}
AND is_deleted = 0 ) OR ma.patient_id IN ( SELECT patient_id FROM medical_record WHERE clinic_id IN
#{clinicId}
AND is_deleted = 0 ) OR ma.patient_id IN ( SELECT patient_id FROM patient_doctor_rel WHERE clinic_id IN
#{clinicId}
AND status = 1 ) )
AND 1 = 0
AND ma.patient_id IN ( SELECT patient_id FROM patient_doctor_rel WHERE doctor_id = #{staffId} AND status = 1 UNION SELECT patient_id FROM appointment WHERE doctor_id = #{staffId} AND is_deleted = 0 UNION SELECT patient_id FROM medical_record WHERE doctor_id = #{staffId} AND is_deleted = 0 UNION SELECT patient_id FROM treatment_plan WHERE doctor_id = #{staffId} AND is_deleted = 0 )
AND 1 = 0
AND ma.patient_id = #{query.patientId}
AND ma.level_id = #{query.levelId}
AND ma.member_status = #{query.memberStatus}
AND ( ma.member_no LIKE CONCAT('%', #{query.keyword}, '%') OR p.patient_name LIKE CONCAT('%', #{query.keyword}, '%') OR p.mobile LIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY ma.created_at DESC, ma.id DESC

